@asset(
    group_name="Kitsu",
    compute_kind="python",
)
def apt_packages_build_kitsu(
        context: AssetExecutionContext,
) -> dict[str, list[str]]:
    """
    """

    ret = dict()

    ret["base"] = [
        "htop",
        "curl",
    ]

    yield Output(ret)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(ret),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "apt_packages_build_kitsu": AssetIn(),
    },
)
def build_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
        apt_packages_build_kitsu: dict[str, list[str]],
) -> str:
    """
    """

    docker_file = pathlib.Path(
        env_base["DOT_LANDSCAPES"],
        env_base.get("LANDSCAPE", "default"),
        "Dockerfiles",
        context.asset_key.path[-1],
        "Dockerfile",
    )

    tags = [
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:latest",
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{env_base.get('LANDSCAPE', str(time.time()))}",
    ]

    apt_install_str_base: str = get_apt_install_str(
        apt_install_packages=apt_packages_build_kitsu["base"],
    )

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        # {dagster_url}
        # https://hub.docker.com/r/cgwire/cgwire
        FROM cgwire/cgwire:latest AS {image_name}
        LABEL authors="{AUTHOR}"
        
        SHELL ["/bin/bash", "-c"]
        
        ARG DEBIAN_FRONTEND=noninteractive
        
        ENV CONTAINER_TIMEZONE={TIMEZONE}
        ENV SET_CONTAINER_TIMEZONE=true
        
        RUN apt-get update && apt-get upgrade -y
        
        {apt_install_str_base}
        
        RUN apt-get clean
        
        WORKDIR /opt/zou
        
        ENTRYPOINT []
    """).format(
        apt_install_str_base=apt_install_str_base,
        auto_generated=f"AUTO-GENERATED by Dagster Asset {context.asset_key.path[-1]}",
        dagster_url=urllib.parse.quote(f"http://localhost:3000/asset-groups/{context.asset_key.path[-1]}", safe=":/%"),
        image_name=context.asset_key.path[-1],
        **env_base,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )


