@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "script_prepare_db_kitsu": AssetIn(),
    },
)
def prepare_db_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
        script_prepare_db_kitsu: dict[str, str],
):

    stdout_stderr = {
        "stdout": MetadataValue.md(f"```shell\nNone\n```"),
        "stderr": MetadataValue.md(f"```shell\nNone\n```"),
    }

    if not KITSUDB_INSIDE_CONTAINER:

        kitsu_db_dir_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION")) / "postgresql" / "14" / "main"
        kitsu_db_dir_host.mkdir(parents=True, exist_ok=True)

        kitsu_db_template = env_base.get("KITSU_TEMPLATE_DB_14")

        try:
            empty = not any(kitsu_db_dir_host.iterdir())
        except PermissionError as e:
            context.log.warning(
                f"Database folder {kitsu_db_dir_host} already "
                f"exists and/or is not writable: "
                f"{e}")
            empty = False

        if empty:
            shutil.copytree(
                src=kitsu_db_template,
                dst=kitsu_db_dir_host,
                dirs_exist_ok=True,
            )

        if bool(script_prepare_db_kitsu["script"]):

            context.log.info(f"Setting ownership of {kitsu_db_dir_host.as_posix()}...")

            proc = subprocess.Popen(
                script_prepare_db_kitsu["exe"],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                stdin=subprocess.PIPE,
                env={
                    "SSH_PASS": env_base['SSH_PASS'],
                }
            )

            stdout, stderr = proc.communicate(
                input=script_prepare_db_kitsu["script"].encode(),
            )

            stdout_stderr = {
                "stdout": MetadataValue.md(f"```shell\n{stdout.decode(encoding='utf-8')}\n```"),
                "stderr": MetadataValue.md(f"```shell\n{stderr.decode(encoding='utf-8')}\n```"),
            }

            # Todo:
            #  - [ ] implement reliable verification whether successful or not

    return MaterializeResult(
        asset_key=context.asset_key,
        metadata={
            **stdout_stderr,
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
    },
)
def script_init_zou(
        context: AssetExecutionContext,
        env_base: dict,
) -> dict[str, str]:
    """This script overrides the default
    Kitsu `/opt/zou/init_zou.sh` to be able
    to specify custom DB username and password"""

    # Todo
    #  - [ ] Custom username and password don't work yet

    ret = dict()

    ret["exe"] = shutil.which("bash")
    ret["script"] = str()

    # Source:
    # /opt/zou/init_zou.sh
    kitsu_admin_user = env_base.get("KITSU_ADMIN_USER", "admin@example.com")
    kitsu_admin_password = env_base.get("KITSU_ADMIN_PASSWORD", "mysecretpassword")

    ret["script"] += "#!/bin/bash\n"
    ret["script"] += "export LC_ALL=C.UTF-8\n"
    ret["script"] += "export LANG=C.UTF-8\n"
    ret["script"] += "\n"
    ret["script"] += "service postgresql start\n"
    ret["script"] += "service redis-server start\n"
    ret["script"] += "\n"
    ret["script"] += ". /opt/zou/env/bin/activate\n"
    ret["script"] += "\n"
    ret["script"] += "zou upgrade-db\n"
    ret["script"] += "zou init-data\n"
    ret["script"] += f"zou create-admin {kitsu_admin_user} --password {kitsu_admin_password}\n"
    ret["script"] += "\n"
    ret["script"] += "service postgresql stop\n"
    ret["script"] += "service redis-server stop\n"
    ret["script"] += "\n"
    ret["script"] += "echo Success\n"
    ret["script"] += "\n"
    ret["script"] += "exit 0\n"

    yield Output(ret)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(ret),
            "script_init_zou": MetadataValue.md(f"```shell\n{ret['script']}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "script_init_zou": AssetIn(),
        "build_kitsu": AssetIn(),
    },
    deps=[
        "prepare_db_kitsu",
    ],
)
def compose_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
        script_init_zou: dict,
        build_kitsu: str,
) -> dict:
    """
    """

    # INIT_ZOU.SH
    script_init_zou_path = pathlib.Path(
        env_base.get('KITSU_INIT_ZOU'),
    )

    script_init_zou_path.parent.mkdir(parents=True, exist_ok=True)

    with open(
        file=script_init_zou_path,
        mode="w",
    ) as sh_init_zou:
        sh_init_zou.write(script_init_zou["script"])

    # # INIT_AND_START_ZOU.SH
    # script_init_and_start_zou = pathlib.Path(
    #     env_base.get('KITSU_INIT_AND_START_ZOU'),
    # )
    #
    # script_init_and_start_zou.parent.mkdir(parents=True, exist_ok=True)
    #
    # with open(
    #     file=script_init_and_start_zou,
    #     mode="w",
    # ) as sh_init_and_start_zou:
    #     sh_init_and_start_zou.write("#!/bin/bash\n")
    #     sh_init_and_start_zou.write("export LC_ALL=C.UTF-8\n")
    #     sh_init_and_start_zou.write("export LANG=C.UTF-8\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("if [ -z \"$( ls -A '/var/lib/postgresql/14/main' )\" ]; then\n")
    #     sh_init_and_start_zou.write("\tbash /opt/zou/init_zou.sh\n")
    #     sh_init_and_start_zou.write("\techo \"Kitsu DB initialized successfully\"\n")
    #     sh_init_and_start_zou.write("fi\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("bash /opt/zou/start_zou.sh\n")
    #     # sh_init_and_start_zou.write("\n")
    #     # sh_init_and_start_zou.write("echo Success\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("exit 0\n")

    # compile_cmds(
    #     docker_file=build_kitsu,
    #     tag=
    # )

    cmd_docker_run = [
        shutil.which("docker"),
        "run",
        "--rm",
        "--interactive",
        "--tty",
        build_kitsu,
        "/bin/bash",
    ]

    volumes = [
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT')}",
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT_LNS')}",
        # f"{env_base.get('KITSU_INIT_AND_START_ZOU')}:/opt/zou/init_and_start_zou.sh",
        f"{env_base.get('KITSU_INIT_ZOU')}:/opt/zou/init_zou.sh",
    ]

    if not KITSUDB_INSIDE_CONTAINER:

        kitsu_db_dir_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION")) / "postgresql" / "14" / "main"

        volumes.insert(
            0,
            f"{kitsu_db_dir_host.as_posix()}:/var/lib/postgresql/14/main",
        )

        kitsu_previews_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION")) / "previews"
        kitsu_previews_host.mkdir(parents=True, exist_ok=True)

        volumes.insert(
            1,
            f"{kitsu_previews_host}:/opt/zou/previews",
        )

    docker_dict = {
        "services": {
            "kitsu": {
                "container_name": "kitsu",
                "hostname": "kitsu",
                "domainname": env_base.get("ROOT_DOMAIN"),
                "restart": "always",
                "image": build_kitsu,
                "volumes": volumes,
                "healthcheck": {
                    "test": ["CMD", "curl", "-f", f"http://localhost:{env_base.get('KITSU_PORT_CONTAINER')}"],
                    "interval": "10s",
                    "timeout": "2s",
                    "retries": "3",
                },
                "command": [
                    "bash",
                    "/opt/zou/start_zou.sh",
                ],
                "ports": [
                    f"{env_base.get('KITSU_PORT_HOST')}:{env_base.get('KITSU_PORT_CONTAINER')}",
                ],
            },
        },
    }

    docker_yaml = yaml.dump(docker_dict)

    yield Output(docker_dict)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(docker_dict),
            "docker_dict": MetadataValue.md(f"```json\n{json.dumps(docker_dict, indent=2)}\n```"),
            "docker_yaml": MetadataValue.md(f"```yaml\n{docker_yaml}\n```"),
            "cmd_docker_run": MetadataValue.path(cmd_list_to_str(cmd_docker_run)),
            "env_base": MetadataValue.json(env_base),
        },
    )
